import{_ as n,o as s,c as t,af as a}from"./chunks/framework.DZTH9Z-c.js";const g=JSON.parse('{"title":"Platform Architecture","description":"Detailed Coreness architecture description. Event-driven system, plugins, DI container, multitenancy and project structure.","frontmatter":{"title":"Platform Architecture","description":"Detailed Coreness architecture description. Event-driven system, plugins, DI container, multitenancy and project structure.","keywords":"coreness architecture, event-driven, dependency injection, plugins, multitenancy","head":[["meta",{"property":"og:title","content":"Platform Architecture | Coreness"}],["meta",{"property":"og:description","content":"Detailed Coreness architecture description. Event-driven system, plugins, DI container, multitenancy and project structure."}],["meta",{"property":"og:image","content":"https://docs.coreness.tech/logo-dark.png"}],["meta",{"property":"og:url","content":"https://docs.coreness.tech/en/advanced/ARCHITECTURE"}],["link",{"rel":"canonical","href":"https://docs.coreness.tech/en/advanced/ARCHITECTURE"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Platform Architecture\\",\\"description\\":\\"Detailed Coreness architecture description. Event-driven system, plugins, DI container, multitenancy and project structure.\\",\\"url\\":\\"https://docs.coreness.tech/en/advanced/ARCHITECTURE\\"}"]]},"headers":[],"relativePath":"en/advanced/ARCHITECTURE.md","filePath":"en/advanced/ARCHITECTURE.md"}'),i={name:"en/advanced/ARCHITECTURE.md"};function r(o,e,l,c,p,d){return s(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="project-architecture" tabindex="-1">Project Architecture <a class="header-anchor" href="#project-architecture" aria-label="Permalink to &quot;Project Architecture&quot;">​</a></h1><h2 id="⚠️-system-requirements" tabindex="-1">⚠️ System Requirements <a class="header-anchor" href="#⚠️-system-requirements" aria-label="Permalink to &quot;⚠️ System Requirements&quot;">​</a></h2><h3 id="python-version" tabindex="-1">Python Version <a class="header-anchor" href="#python-version" aria-label="Permalink to &quot;Python Version&quot;">​</a></h3><ul><li><strong>✅ Recommended:</strong> Python 3.11</li><li><strong>❌ Not recommended:</strong> Python 3.12+ (may work incorrectly or not work at all)</li><li><strong>ℹ️ Reason:</strong> Dependencies on specific library and API versions</li></ul><h2 id="libraries-used" tabindex="-1">Libraries Used <a class="header-anchor" href="#libraries-used" aria-label="Permalink to &quot;Libraries Used&quot;">​</a></h2><ul><li><strong>SQLAlchemy</strong> — ORM for database operations</li><li><strong>PyYAML</strong> — YAML config parsing</li><li><strong>psycopg2-binary</strong> — PostgreSQL connection driver</li><li><strong>python-dotenv</strong> — environment variable loading</li><li><strong>unidecode</strong> — transliteration</li><li><strong>emoji</strong> — emoji support</li><li><strong>requests</strong> — HTTP client for external API requests (tools, dev)</li><li><strong>aiohttp</strong> — asynchronous HTTP client for Telegram Bot API</li><li><strong>openai</strong> — library for OpenAI API via OpenRouter</li><li><strong>gitpython</strong> — Git repository operations (deployment, updates)</li><li><strong>telegramify-markdown</strong> — Markdown to Telegram MarkdownV2 format conversion</li><li><strong>croniter</strong> — cron expression parsing for scheduled scenarios</li><li><strong>pydantic</strong> — data validation against config.yaml schemas</li><li><strong>cryptography</strong> — self-signed SSL certificate generation for Telegram webhooks</li><li><strong>pgvector</strong> — vector data operations in PostgreSQL for RAG (Retrieval-Augmented Generation)</li><li><strong>python-dateutil</strong> — date and time interval handling (correct month/year processing, month edges)</li></ul><h3 id="deployment-system-dependencies" tabindex="-1">Deployment System Dependencies <a class="header-anchor" href="#deployment-system-dependencies" aria-label="Permalink to &quot;Deployment System Dependencies&quot;">​</a></h3><p>Deployment utility (<code>tools/deployment/</code>) uses additional libraries:</p><ul><li><strong>gitpython</strong> — repository cloning, Git operations</li><li><strong>requests</strong> — GitHub API interaction for creating Merge Requests</li><li><strong>PyYAML</strong> — deployment configuration parsing (<code>config.yaml</code>)</li><li><strong>python-dotenv</strong> — environment variable loading (tokens, API keys)</li></ul><h2 id="operational-database" tabindex="-1">Operational Database <a class="header-anchor" href="#operational-database" aria-label="Permalink to &quot;Operational Database&quot;">​</a></h2><p>The project supports <strong>two databases</strong> with preset switching:</p><ul><li><strong>SQLite</strong> — local database for small projects (simple setup)</li><li><strong>PostgreSQL</strong> — production database for production (high performance, scalability)</li></ul><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><ul><li><strong>Microservice Architecture</strong>: each service operates independently and self-sufficiently</li><li><strong>Event Driven Architecture</strong>: all actions are initiated by events, processed by orchestrator</li><li><strong>Vertical Slice Architecture</strong>: each service is independent, receives only necessary data, doesn&#39;t depend on other services</li><li><strong>Configurability</strong>: all logic and routing are externalized to yaml configs</li><li><strong>Layer Isolation</strong>: clear responsibility separation between layers with dependency hierarchy</li><li><strong>Inter-service Communication</strong> — only through DB, except rare cases when a service provides public methods (API) for integration or special tasks</li></ul><h2 id="layers-and-their-purpose" tabindex="-1">Layers and Their Purpose <a class="header-anchor" href="#layers-and-their-purpose" aria-label="Permalink to &quot;Layers and Their Purpose&quot;">​</a></h2><h3 id="foundation-foundation-—-fundamental-utilities" tabindex="-1"><strong>Foundation (foundation)</strong> — Fundamental Utilities <a class="header-anchor" href="#foundation-foundation-—-fundamental-utilities" aria-label="Permalink to &quot;**Foundation (foundation)** — Fundamental Utilities&quot;">​</a></h3><ul><li><strong>Purpose:</strong> Critically important utilities required to create DI-container and launch application.</li><li><strong>Location:</strong> <code>plugins/utilities/foundation/</code></li><li><strong>Can use:</strong> Only Python system libraries.</li></ul><h3 id="custom-layers-—-thematic-utility-layers" tabindex="-1"><strong>Custom Layers</strong> — Thematic Utility Layers <a class="header-anchor" href="#custom-layers-—-thematic-utility-layers" aria-label="Permalink to &quot;**Custom Layers** — Thematic Utility Layers&quot;">​</a></h3><ul><li><strong>Purpose:</strong> Utilities for specific technologies or platforms (Telegram, API, databases, etc.).</li><li><strong>Location:</strong> <code>plugins/utilities/[layer_name]/</code> (e.g., <code>telegram/</code>, <code>ai/</code>, <code>database/</code>)</li><li><strong>Can use:</strong> Foundation and utilities within its own layer (cross-layer usage not recommended).</li></ul><h3 id="core-core-—-infrastructure-utilities" tabindex="-1"><strong>Core (core)</strong> — Infrastructure Utilities <a class="header-anchor" href="#core-core-—-infrastructure-utilities" aria-label="Permalink to &quot;**Core (core)** — Infrastructure Utilities&quot;">​</a></h3><ul><li><strong>Purpose:</strong> Utilities for event creation and processing, DB queue writing, database operations. Highest utility level.</li><li><strong>Location:</strong> <code>plugins/utilities/core/</code></li><li><strong>Can use:</strong> Foundation, custom-layers, and other core utilities.</li></ul><h3 id="services-services-—-business-services" tabindex="-1"><strong>Services (services)</strong> — Business Services <a class="header-anchor" href="#services-services-—-business-services" aria-label="Permalink to &quot;**Services (services)** — Business Services&quot;">​</a></h3><ul><li><strong>Purpose:</strong> Core business logic of the application, plugins with specific functionality.</li><li><strong>Location:</strong> <code>plugins/services/</code></li><li><strong>Can use:</strong> Foundation, custom-layers, and core utilities.</li></ul><p>📋 <strong>Practical Layer Usage Examples:</strong> <a href="./PLUGINS_GUIDE#practical-layer-usage-examples">Plugin Guide</a></p><h2 id="dependency-hierarchy" tabindex="-1">Dependency Hierarchy <a class="header-anchor" href="#dependency-hierarchy" aria-label="Permalink to &quot;Dependency Hierarchy&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Foundation (logger, plugins_manager, settings_manager)</span></span>
<span class="line"><span>    ↑</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Custom Layers  │</span></span>
<span class="line"><span>│ (telegram, etc) │</span></span>
<span class="line"><span>└─────────────────┘</span></span>
<span class="line"><span>    ↑</span></span>
<span class="line"><span>┌────────┐</span></span>
<span class="line"><span>│  Core  │</span></span>
<span class="line"><span>│  ───&gt;  │</span></span>
<span class="line"><span>└────────┘</span></span>
<span class="line"><span>    ↑</span></span>
<span class="line"><span>Services</span></span></code></pre></div><h3 id="dependency-rules" tabindex="-1">Dependency Rules <a class="header-anchor" href="#dependency-rules" aria-label="Permalink to &quot;Dependency Rules&quot;">​</a></h3><ol><li><strong>Foundation</strong> — use only Python system libraries</li><li><strong>Custom Layers</strong> — use foundation and utilities within their layer (cross-layer usage not recommended)</li><li><strong>Core</strong> — use foundation, custom-layers, and other core utilities</li><li><strong>Services</strong> — use foundation, custom-layers, and core utilities</li><li><strong>Circular dependencies</strong> are <strong>FORBIDDEN</strong></li></ol><p>📋 <strong>Dependency Examples and Practical Recommendations:</strong> <a href="./PLUGINS_GUIDE#dependency-system">Plugin Guide</a></p><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/                    # Core application</span></span>
<span class="line"><span>├── application.py      # Entry point and orchestrator</span></span>
<span class="line"><span>└── di_container.py     # Dependency container</span></span>
<span class="line"><span></span></span>
<span class="line"><span>plugins/                # Plugins (utilities and services)</span></span>
<span class="line"><span>├── utilities/          # Supporting utility layers</span></span>
<span class="line"><span>│   ├── foundation/     # Fundamental utilities (logger, plugins_manager)</span></span>
<span class="line"><span>│   ├── telegram/       # Telegram utilities (tg_bot_api, tg_utils)</span></span>
<span class="line"><span>│   ├── ai/             # AI utilities (ai_client)</span></span>
<span class="line"><span>│   └── core/           # Core utilities (event_processor, database_service)</span></span>
<span class="line"><span>└── services/           # Business services (plugins)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>utils/                  # System utilities</span></span>
<span class="line"><span>├── database/           # DB utilities (migrations, updates)</span></span>
<span class="line"><span>├── updater/            # Core update utilities</span></span>
<span class="line"><span>└── ...                 # Other system utilities</span></span>
<span class="line"><span></span></span>
<span class="line"><span>config/                 # Business configuration</span></span>
<span class="line"><span>└── settings.yaml       # Global system settings</span></span></code></pre></div><p>📋 <strong>Plugin Creation Rules and Folder Structure:</strong> <a href="./PLUGINS_GUIDE#plugin-creation-rules">Plugin Guide</a></p><h2 id="processing-flow" tabindex="-1">Processing Flow <a class="header-anchor" href="#processing-flow" aria-label="Permalink to &quot;Processing Flow&quot;">​</a></h2><ol><li><strong>Application</strong> (<code>app/application.py</code>) initializes foundation utilities (logger, plugins_manager), collects information about all plugins, registers them, creates dependency container, and starts all services.</li><li><strong>Core</strong> utilities (<code>plugins/utilities/core/</code>) receive events from external sources (e.g., Telegram Bot API via HTTP, external services), process them, and pass to orchestrator.</li><li><strong>Orchestrator</strong> analyzes events, finds matching scenarios, and creates execution tasks.</li><li><strong>Services</strong> (<code>plugins/services/</code>) execute business logic through core method calls.</li><li><strong>Inter-service Communication</strong> — only through DB.</li></ol><p>📋 <strong>Initialization Algorithm and Loading Order:</strong> <a href="./PLUGINS_GUIDE#initialization-and-loading-order">Plugin Guide</a></p>`,35)])])}const h=n(i,[["render",r]]);export{g as __pageData,h as default};
